import { formatDate } from '@ui/utils';
import { tw } from '@utils/useTailwind';
import { clsx } from 'clsx';
import { createContext, ReactNode, useContext, useEffect, useRef, useState } from 'react';
import { Button } from '../../../Button';
import { Checkbox } from '../../../Checkbox';
import { Label } from '../../../Label';

type Props = {
  amount: string;
  date: string;
  isChecked?: boolean;
  message?: string;
  onClick?: () => void;
};

type FuturePledgeContextType = {
  highlight: () => void;
  isHighlighted: boolean;
};
export const FuturePledgeContext = createContext<FuturePledgeContextType>({
  highlight: () => null,
  isHighlighted: false,
});

export const FuturePledgeProvider = ({ children }: { children: ReactNode }) => {
  const [highlight, setHighlight] = useState(false);
  useEffect(() => {
    if (highlight) {
      setTimeout(() => {
        setHighlight(false);
      }, 2000);
    }
  }, [highlight]);

  return (
    <FuturePledgeContext.Provider
      value={{
        highlight: () => setHighlight(true),
        isHighlighted: highlight,
      }}
    >
      {children}
    </FuturePledgeContext.Provider>
  );
};

export const FuturePledgeBanner = ({ amount, date, isChecked, message, onClick }: Props) => {
  const { isHighlighted } = useContext(FuturePledgeContext);
  const innerRef = useRef<HTMLButtonElement>(null);
  // biome-ignore lint/correctness/useExhaustiveDependencies: intentional extra dependencies
  useEffect(() => {
    if (isHighlighted) {
      innerRef.current?.scrollIntoView({
        behavior: 'smooth',
        block: 'center',
      });
      innerRef.current?.focus();
    }
  }, [isHighlighted, innerRef]);

  const classes = clsx(
    isChecked ? (isHighlighted ? 'bg-yellow-500' : 'bg-yellow-200') : 'bg-neutral-0',
    isChecked ? 'border-yellow-500' : 'border-yellow-400',
    tw`mt-4 flex !h-auto w-full cursor-pointer flex-col !items-start gap-4 rounded-md border !p-4 pt-3
    transition-[background-color] duration-500`
  );

  return (
    <Button
      className={classes}
      data-checked={isChecked ? '' : undefined}
      onClick={(e) => {
        onClick?.();
        e.preventDefault();
      }}
      ref={innerRef}
      variant="unstyled"
    >
      {message && (
        <div className="flex flex-col gap-1">
          {message.split('\n').map((part) => (
            <Label className="leading-[25.5px]" key={part} variant="regular">
              {part}
            </Label>
          ))}
        </div>
      )}
      <Checkbox isChecked={isChecked} onChange={onClick} value="0" variant="darkCheckbox">
        <Label variant="regular">
          {`Donate an additional ${amount} automatically on ${formatDate(date, 'MM/dd')}`}
        </Label>
      </Checkbox>
    </Button>
  );
};
